    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to hold aggregated results
    aggregated_results = defaultdict(lambda: {
        'scores': [],
        'texts': [],
        'metadata': defaultdict(list)
    })

    # Extract top-level fields and metadata for each result
    for result in search_results:
        # Extract group value from metadata or top-level fields
        group_value = result.metadata.get(group_by_field)

        # Handle missing grouping field values
        if group_value is None or group_value == "":
            group_value = 'unknown'

        # Extract field values from SearchResult objects
        # Check top-level attributes first, then metadata
        top_level_fields = ['id', 'score', 'text']
        result_data = {}

        # Extract top-level fields
        for field in top_level_fields:
            if hasattr(result, field):
                result_data[field] = getattr(result, field)

        # Extract metadata fields
        for key, value in result.metadata.items():
            if key not in top_level_fields:
                result_data[key] = value

        # Accumulate data for aggregation
        group_data = aggregated_results[group_value]

        # Collect scores for default statistics
        if 'score' in result_data:
            group_data['scores'].append(result_data['score'])

        # Collect texts
        if 'text' in result_data:
            group_data['texts'].append(result_data['text'])

        # Collect metadata fields for custom aggregation
        for field, value in result_data.items():
            if field != 'score' and field != 'text':
                group_data['metadata'][field].append(value)

    # Compute statistics for each group
    final_results = {}

    for group_value, group_data in aggregated_results.items():
        # Calculate default statistics
        stats = {}

        # Count of results in group
        count = len(group_data['scores'])
        stats['count'] = count

        # Average score calculation
        if count > 0:
            avg_score = sum(group_data['scores']) / count
            stats['avg_score'] = avg_score
            stats['max_score'] = max(group_data['scores'])
            stats['min_score'] = min(group_data['scores'])
        else:
            stats['avg_score'] = 0
            stats['max_score'] = 0
            stats['min_score'] = 0

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, agg_func in aggregation_funcs.items():
                # Check if field exists in group data
                if field_name in group_data['metadata']:
                    field_values = group_data['metadata'][field_name]
                    if field_values:
                        try:
                            stats[field_name] = agg_func(field_values)
                        except Exception as e:
                            # Handle potential errors in custom functions
                            stats[field_name] = f"Error: {str(e)}"
                    else:
                        stats[field_name] = None
                else:
                    stats[field_name] = None

        final_results[group_value] = stats

    return final_results

